// Convert bare URLs in each guide's “Additional Resources” section into
// readable labels from the resource-title CSV generated by
// update_external_resource_titles.py.
//
// Explicitly written Markdown link text is always preserved. If the CSV is
// missing, unreadable, or has no matching row, the plugin falls back to a
// readable label derived from the URL so the site build still succeeds.

import { existsSync, readFileSync, statSync } from "node:fs";
import { fileURLToPath } from "node:url";

const RESOURCE_CSV_PATH = fileURLToPath(
  new URL("./src/data/external-resource-titles.csv", import.meta.url),
);

const TRACKING_QUERY_NAMES = new Set([
  "dclid",
  "fbclid",
  "gclid",
  "mc_cid",
  "mc_eid",
]);

const HOST_LABELS = new Map([
  ["bankofengland.co.uk", "Bank of England"],
  ["citizensadvice.org.uk", "Citizens Advice"],
  ["consumer.ftc.gov", "Federal Trade Commission"],
  ["consumerfinance.gov", "Consumer Financial Protection Bureau"],
  ["cdc.gov", "Centers for Disease Control and Prevention"],
  ["deathnotificationservice.co.uk", "Death Notification Service"],
  ["fca.org.uk", "Financial Conduct Authority"],
  ["financial-ombudsman.org.uk", "Financial Ombudsman Service"],
  ["frbservices.org", "Federal Reserve Financial Services"],
  ["gov.scot", "Scottish Government"],
  ["gov.uk", "GOV.UK"],
  ["helpwithmybank.gov", "HelpWithMyBank.gov"],
  ["labc.co.uk", "Local Authority Building Control"],
  ["moneyhelper.org.uk", "MoneyHelper"],
  ["nacha.org", "Nacha"],
  ["nationalgas.com", "National Gas"],
  ["nationalgrid.com", "National Grid"],
  ["nhs.uk", "NHS"],
  ["nidirect.gov.uk", "nidirect"],
  ["nienetworks.co.uk", "NIE Networks"],
  ["occ.treas.gov", "Office of the Comptroller of the Currency"],
  ["osha.gov", "Occupational Safety and Health Administration"],
  ["phoenixenergyni.com", "Phoenix Energy"],
  ["usa.gov", "USA.gov"],
  ["usgs.gov", "U.S. Geological Survey"],
  ["wearepay.uk", "Pay.UK"],
]);

const GENERIC_PATH_PARTS = new Set([
  "about",
  "article",
  "articles",
  "consumer",
  "consumers",
  "content",
  "en",
  "en-gb",
  "en-us",
  "guidance",
  "help",
  "home",
  "index",
  "information",
  "page",
  "pages",
  "publication",
  "publications",
  "resource",
  "resources",
  "service",
  "services",
  "topic",
  "topics",
  "what-we-do",
]);

const UPPERCASE_WORDS = new Map([
  ["ach", "ACH"],
  ["bacs", "Bacs"],
  ["cdc", "CDC"],
  ["chaps", "CHAPS"],
  ["covid", "COVID"],
  ["faq", "FAQ"],
  ["faqs", "FAQs"],
  ["fca", "FCA"],
  ["fema", "FEMA"],
  ["ftc", "FTC"],
  ["irs", "IRS"],
  ["nhs", "NHS"],
  ["osha", "OSHA"],
  ["pdf", "PDF"],
  ["ssa", "SSA"],
  ["uk", "UK"],
  ["us", "US"],
  ["usa", "USA"],
]);

function textFromNode(node) {
  if (!node) return "";
  if (node.type === "text") return String(node.value || "");
  if (!Array.isArray(node.children)) return "";
  return node.children.map(textFromNode).join("");
}

function normalizeComparable(value) {
  return String(value || "")
    .trim()
    .replace(/\/$/, "")
    .replace(/^https?:\/\//i, "")
    .toLowerCase();
}

function normalizeUrlForLookup(value) {
  let url;
  try {
    url = new URL(String(value || "").trim());
  } catch {
    return "";
  }

  if (!/^https?:$/.test(url.protocol)) return "";

  url.hash = "";
  url.hostname = url.hostname.toLowerCase();

  if (
    (url.protocol === "http:" && url.port === "80") ||
    (url.protocol === "https:" && url.port === "443")
  ) {
    url.port = "";
  }

  url.pathname = (url.pathname || "/").replace(/\/{2,}/g, "/");

  // Treat a trailing slash as equivalent for normal page URLs. The scraper,
  // Markdown source, browser, or redirected destination may use either form.
  // Keep the root path as "/".
  if (url.pathname !== "/") {
    url.pathname = url.pathname.replace(/\/+$/, "");
  }

  for (const key of [...url.searchParams.keys()]) {
    const lower = key.toLowerCase();
    if (lower.startsWith("utm_") || TRACKING_QUERY_NAMES.has(lower)) {
      url.searchParams.delete(key);
    }
  }

  return url.toString();
}

function parseCsv(source) {
  const rows = [];
  let row = [];
  let field = "";
  let quoted = false;

  const text = String(source || "").replace(/^\uFEFF/, "");

  for (let index = 0; index < text.length; index += 1) {
    const character = text[index];

    if (quoted) {
      if (character === '"') {
        if (text[index + 1] === '"') {
          field += '"';
          index += 1;
        } else {
          quoted = false;
        }
      } else {
        field += character;
      }
      continue;
    }

    if (character === '"' && field.length === 0) {
      quoted = true;
    } else if (character === ",") {
      row.push(field);
      field = "";
    } else if (character === "\n") {
      row.push(field.replace(/\r$/, ""));
      rows.push(row);
      row = [];
      field = "";
    } else {
      field += character;
    }
  }

  if (field.length > 0 || row.length > 0) {
    row.push(field.replace(/\r$/, ""));
    rows.push(row);
  }

  return rows;
}

function rowLabel(row) {
  const manualOverride = String(row.manual_override || "").trim();
  if (manualOverride) return manualOverride;

  const displayLabel = String(row.display_label || "").trim();
  if (displayLabel) return displayLabel;

  const siteName = String(row.site_name || "").trim();
  const pageTitle = String(row.page_title || "").trim();

  if (siteName && pageTitle) {
    if (normalizeComparable(siteName) === normalizeComparable(pageTitle)) {
      return pageTitle;
    }
    return `${siteName} — ${pageTitle}`;
  }

  return pageTitle || siteName;
}

let cachedResourceLabels = new Map();
let cachedResourceCsvStamp = "";
let lastReportedResourceCsvStamp = "";

function resourceCsvStamp() {
  if (!existsSync(RESOURCE_CSV_PATH)) return "missing";

  const details = statSync(RESOURCE_CSV_PATH);
  return `${details.mtimeMs}:${details.size}`;
}

function loadResourceLabelMap() {
  const map = new Map();

  if (!existsSync(RESOURCE_CSV_PATH)) {
    return map;
  }

  const rows = parseCsv(readFileSync(RESOURCE_CSV_PATH, "utf8"));
  if (rows.length === 0) return map;

  const headers = rows[0].map((value) => String(value || "").trim());

  for (const values of rows.slice(1)) {
    if (values.every((value) => !String(value || "").trim())) continue;

    const row = Object.fromEntries(
      headers.map((header, index) => [header, values[index] ?? ""]),
    );
    const label = rowLabel(row);
    if (!label) continue;

    const candidates = [row.url, row.normalized_url, row.final_url];
    for (const candidate of candidates) {
      const exact = String(candidate || "").trim();
      if (!exact) continue;

      map.set(exact, label);

      const normalized = normalizeUrlForLookup(exact);
      if (normalized) map.set(normalized, label);
    }
  }

  return map;
}

function getResourceLabelMap() {
  let stamp;

  try {
    stamp = resourceCsvStamp();
  } catch (error) {
    console.warn(
      `[PanicStation] Could not inspect resource-title CSV at ${RESOURCE_CSV_PATH}: ` +
        `${error instanceof Error ? error.message : String(error)}. ` +
        "The last successfully loaded labels will be retained.",
    );
    return cachedResourceLabels;
  }

  if (stamp === cachedResourceCsvStamp) {
    return cachedResourceLabels;
  }

  if (stamp === "missing") {
    cachedResourceLabels = new Map();
    cachedResourceCsvStamp = stamp;

    if (lastReportedResourceCsvStamp !== stamp) {
      console.warn(
        `[PanicStation] Resource-title CSV not found at ${RESOURCE_CSV_PATH}. ` +
          "Additional Resources links will use URL-derived fallback labels.",
      );
      lastReportedResourceCsvStamp = stamp;
    }

    return cachedResourceLabels;
  }

  try {
    cachedResourceLabels = loadResourceLabelMap();
    cachedResourceCsvStamp = stamp;

    if (lastReportedResourceCsvStamp !== stamp) {
      console.info(
        `[PanicStation] Loaded ${cachedResourceLabels.size.toLocaleString("en-GB")} ` +
          `resource-title lookup keys from ${RESOURCE_CSV_PATH}.`,
      );
      lastReportedResourceCsvStamp = stamp;
    }
  } catch (error) {
    console.warn(
      `[PanicStation] Could not read resource-title CSV at ${RESOURCE_CSV_PATH}: ` +
        `${error instanceof Error ? error.message : String(error)}. ` +
        "The last successfully loaded labels will be retained.",
    );
  }

  return cachedResourceLabels;
}

function titleCase(value) {
  return String(value || "")
    .split(/\s+/)
    .filter(Boolean)
    .map((word, index) => {
      const lower = word.toLowerCase();
      if (UPPERCASE_WORDS.has(lower)) return UPPERCASE_WORDS.get(lower);
      if (index > 0 && ["and", "for", "in", "of", "on", "the", "to", "with"].includes(lower)) {
        return lower;
      }
      return lower.charAt(0).toUpperCase() + lower.slice(1);
    })
    .join(" ");
}

function hostLabel(hostname) {
  const host = String(hostname || "").toLowerCase().replace(/^www\./, "");

  if (HOST_LABELS.has(host)) return HOST_LABELS.get(host);

  for (const [knownHost, label] of HOST_LABELS) {
    if (host.endsWith(`.${knownHost}`)) return label;
  }

  const multipartSuffixes = [
    "ac.uk",
    "co.uk",
    "gov.au",
    "gov.uk",
    "govt.nz",
    "nhs.uk",
    "org.au",
    "org.uk",
  ];

  for (const suffix of multipartSuffixes) {
    if (host.endsWith(`.${suffix}`)) {
      const prefix = host.slice(0, -(suffix.length + 1));
      const likelyName = prefix.split(".").filter(Boolean).at(-1);
      if (likelyName) return titleCase(likelyName.replace(/[-_]+/g, " "));
    }
  }

  const pieces = host.split(".").filter(Boolean);
  const likelyName = pieces.length >= 2 ? pieces.at(-2) : pieces[0] || host;
  return titleCase(likelyName.replace(/[-_]+/g, " "));
}

function pathLabel(url) {
  const parts = url.pathname
    .split("/")
    .map((part) => {
      try {
        return decodeURIComponent(part);
      } catch {
        return part;
      }
    })
    .map((part) => part.replace(/\.(?:aspx?|html?|php|pdf)$/i, ""))
    .map((part) => part.replace(/[-_]+/g, " ").trim())
    .filter(Boolean)
    .filter((part) => !GENERIC_PATH_PARTS.has(part.toLowerCase()))
    .filter((part) => !/^\d+$/.test(part));

  const candidate = parts.at(-1) || "";
  if (!candidate || candidate.length < 4) return "";

  return titleCase(candidate);
}

function fallbackLabel(href) {
  let url;
  try {
    url = new URL(href);
  } catch {
    return href;
  }

  const organisation = hostLabel(url.hostname);
  const page = pathLabel(url);

  if (!page || normalizeComparable(page) === normalizeComparable(organisation)) {
    return organisation;
  }

  return `${organisation} — ${page}`;
}

function csvLabel(href, resourceLabels) {
  const exact = String(href || "").trim();
  if (resourceLabels.has(exact)) return resourceLabels.get(exact);

  const normalized = normalizeUrlForLookup(exact);
  if (normalized && resourceLabels.has(normalized)) {
    return resourceLabels.get(normalized);
  }

  return "";
}

function isResourcesSection(node) {
  if (node?.type !== "element" || node.tagName !== "section") return false;

  const classes = node.properties?.className;
  return Array.isArray(classes) && classes.includes("ps-resources");
}

function improveLinks(node, resourceLabels, insideResources = false) {
  if (!node || !Array.isArray(node.children)) return;

  const nowInsideResources = insideResources || isResourcesSection(node);

  for (const child of node.children) {
    if (
      nowInsideResources &&
      child?.type === "element" &&
      child.tagName === "a" &&
      typeof child.properties?.href === "string"
    ) {
      const href = child.properties.href;
      const visibleText = textFromNode(child).trim();

      if (
        /^https?:\/\//i.test(href) &&
        normalizeComparable(visibleText) === normalizeComparable(href)
      ) {
        const savedLabel = csvLabel(href, resourceLabels);
        child.children = [
          {
            type: "text",
            value: savedLabel || fallbackLabel(href),
          },
        ];
        child.properties.title = href;
        child.properties["data-ps-source-url"] = href;
        child.properties["data-ps-source-label"] = savedLabel ? "csv" : "fallback";
      }
    }

    improveLinks(child, resourceLabels, nowInsideResources);
  }
}

export default function rehypeResourceLinkLabels() {
  return (tree) => {
    const resourceLabels = getResourceLabelMap();
    improveLinks(tree, resourceLabels, false);
  };
}
